Actionscript.script:
function 根据等级初始数值(等级值)
{
   hp满血值 = _root.根据等级计算值(hp_min,hp_max,等级值) * _root.难度等级;
   空手攻击力 = _root.根据等级计算值(空手攻击力_min,空手攻击力_max,等级值) * _root.难度等级;
   行走X速度 = _root.根据等级计算值(速度_min,速度_max,等级值) / 10;
   行走Y速度 = 行走X速度 / 2;
   跑X速度 = 行走X速度 * 2;
   跑Y速度 = 行走X速度;
   被击硬直度 = _root.根据等级计算值(被击硬直度_min,被击硬直度_max,等级值);
   起跳速度 = -10;
   基本防御力 = _root.根据等级计算值(基本防御力_min,基本防御力_max,等级值);
   防御力 = 基本防御力 + 装备防御力;
   躲闪率 = _root.根据等级计算值(躲闪率_min,躲闪率_max,等级值);
   if(hp == undefined)
   {
      hp = hp满血值;
   }
}
function 非主角外观刷新()
{
   _root.长枪配置(this._name,this.长枪);
   _root.手枪配置(this._name,this.手枪);
   _root.手枪2配置(this._name,this.手枪2);
   _root.手雷配置(this._name,this.手雷);
   _root.刀配置(this._name,this.刀);
   this.脸型 = 脸型;
   tmp_aaa = _root.根据物品名查找属性(头部装备,14);
   if(tmp_aaa[0] == true)
   {
      this.发型 = "";
   }
   else
   {
      this.发型 = 发型;
   }
   this.面具 = _root.根据物品名查找属性(头部装备,15);
   this.身体 = _root.根据物品名查找属性(上装装备,15) + "身体";
   this.上臂 = _root.根据物品名查找属性(上装装备,15) + "上臂";
   this.左下臂 = _root.根据物品名查找属性(上装装备,15) + "左下臂";
   this.右下臂 = _root.根据物品名查找属性(上装装备,15) + "右下臂";
   this.左手 = _root.根据物品名查找属性(手部装备,15) + "左手";
   this.右手 = _root.根据物品名查找属性(手部装备,15) + "右手";
   this.屁股 = _root.根据物品名查找属性(下装装备,15) + "屁股";
   this.左大腿 = _root.根据物品名查找属性(下装装备,15) + "左大腿";
   this.右大腿 = _root.根据物品名查找属性(下装装备,15) + "右大腿";
   this.小腿 = _root.根据物品名查找属性(下装装备,15) + "小腿";
   this.脚 = _root.根据物品名查找属性(脚部装备,15);
   this.刀_装扮 = _root.根据物品名查找属性(刀,15);
   this.长枪_装扮 = _root.根据物品名查找属性(长枪,15);
   this.手枪_装扮 = _root.根据物品名查找属性(手枪,15);
   this.手枪2_装扮 = _root.根据物品名查找属性(手枪2,15);
   this.手雷_装扮 = _root.根据物品名查找属性(手雷,15);
   this.gotoAndPlay("刷新装扮");
   f1 = _root.根据物品名查找属性(头部装备,8);
   f2 = _root.根据物品名查找属性(上装装备,8);
   f3 = _root.根据物品名查找属性(手部装备,8);
   f4 = _root.根据物品名查找属性(下装装备,8);
   f5 = _root.根据物品名查找属性(脚部装备,8);
   装备防御力 = 0;
   if(f1 != undefined)
   {
      装备防御力 += f1;
   }
   if(f2 != undefined)
   {
      装备防御力 += f2;
   }
   if(f3 != undefined)
   {
      装备防御力 += f3;
   }
   if(f4 != undefined)
   {
      装备防御力 += f4;
   }
   if(f5 != undefined)
   {
      装备防御力 += f5;
   }
   防御力 = 基本防御力 + 装备防御力;
   if(防御力 > 90000)
   {
      防御力 = 90000;
   }
}
function 行走()
{
   if(this.右行 == 1 or this.左行 == 1 or this.上行 == 1 or this.下行 == 1)
   {
      if(状态 != 攻击模式 + "跑")
      {
         if(this.右行 == 1)
         {
            方向改变("右");
            状态改变(攻击模式 + "行走");
            移动("右",行走X速度);
         }
         else if(this.左行 == 1)
         {
            方向改变("左");
            状态改变(攻击模式 + "行走");
            移动("左",行走X速度);
         }
         if(this.下行 == 1)
         {
            状态改变(攻击模式 + "行走");
            移动("下",行走Y速度);
         }
         else if(this.上行 == 1)
         {
            状态改变(攻击模式 + "行走");
            移动("上",行走Y速度);
         }
      }
      else
      {
         if(this.右行 == 1)
         {
            方向改变("右");
            状态改变(攻击模式 + "跑");
            移动("右",跑X速度);
         }
         else if(this.左行 == 1)
         {
            方向改变("左");
            状态改变(攻击模式 + "跑");
            移动("左",跑X速度);
         }
         if(this.下行 == 1)
         {
            状态改变(攻击模式 + "跑");
            移动("下",跑Y速度);
         }
         else if(this.上行 == 1)
         {
            状态改变(攻击模式 + "跑");
            移动("上",跑Y速度);
         }
      }
   }
   else
   {
      状态改变(攻击模式 + "站立");
   }
}
function 移动(移动方向, 速度)
{
   var _loc5_ = {x:this._x,y:this.Z轴坐标};
   _root.gameworld.localToGlobal(_loc5_);
   xx = _loc5_.x;
   yy = _loc5_.y;
   if(移动方向 == "右" and this._x + 速度 < _root.Xmax and _root.gameworld.地图.hitTest(xx + 速度,yy,true) == false)
   {
      this._x += 速度;
   }
   else if(移动方向 == "左" and this._x - 速度 > _root.Xmin and _root.gameworld.地图.hitTest(xx - 速度,yy,true) == false)
   {
      this._x -= 速度;
   }
   if(移动方向 == "下" and this._y + 速度 < _root.Ymax and _root.gameworld.地图.hitTest(xx,yy + 速度,true) == false)
   {
      Z轴坐标 += 速度;
      this._y = Z轴坐标;
      this.swapDepths(this._y);
   }
   else if(移动方向 == "上" and this._y - 速度 > _root.Ymin and _root.gameworld.地图.hitTest(xx,yy - 速度,true) == false)
   {
      Z轴坐标 -= 速度;
      this._y = Z轴坐标;
      this.swapDepths(this._y);
   }
}
function 被击移动_无(移动方向, 速度, 摩擦力)
{
   移动钝感硬直(_root.钝感硬直时间);
   减速度 = 摩擦力;
   speed = 速度;
   if(移动方向 == "右")
   {
      this.onEnterFrame = function()
      {
         if(硬直中 == false)
         {
            speed -= 减速度;
            this.移动("右",speed);
            if(speed <= 0)
            {
               delete this.onEnterFrame;
            }
         }
      };
   }
   else
   {
      this.onEnterFrame = function()
      {
         if(硬直中 == false)
         {
            speed -= 减速度;
            this.移动("左",speed);
            if(speed <= 0)
            {
               delete this.onEnterFrame;
            }
         }
      };
   }
}
function 拾取()
{
   状态改变("拾取");
}
function 跳()
{
   if(状态 == 攻击模式 + "站立")
   {
      跳横移速度 = 0;
   }
   else if(状态 == 攻击模式 + "行走")
   {
      跳横移速度 = 行走X速度;
   }
   else if(状态 == 攻击模式 + "跑")
   {
      跳横移速度 = 跑X速度;
   }
   this.动画是否正在播放 = true;
   状态改变(攻击模式 + "跳");
}
function 状态改变(新状态名)
{
   状态 = 新状态名;
   this.gotoAndStop(新状态名);
}
function 动画完毕()
{
   状态改变(攻击模式 + "站立");
}
function 硬直(目标, 时间)
{
   function pause()
   {
      eval(目标).play();
      clearInterval(pauseInterval);
   }
   clearInterval(pauseInterval);
   eval(目标).stop();
   pauseInterval = setInterval(pause,时间);
}
function 移动钝感硬直(时间)
{
   function pause2()
   {
      硬直中 = false;
      clearInterval(pauseInterval2);
   }
   硬直中 = true;
   clearInterval(pauseInterval2);
   pauseInterval2 = setInterval(pause2,时间);
}
function 攻击模式切换(模式)
{
   if(模式 == "空手")
   {
      攻击模式 = 模式;
      gotoAndStop("攻击模式切换");
   }
   if(模式 == "手雷" and 手雷 != "")
   {
      攻击模式 = 模式;
      gotoAndStop("攻击模式切换");
   }
   if(模式 == "长枪" and 长枪 != "")
   {
      攻击模式 = 模式;
      gotoAndStop("攻击模式切换");
   }
   if(模式 == "兵器" and 刀 != "")
   {
      攻击模式 = 模式;
      gotoAndStop("攻击模式切换");
   }
   if(模式 == "手枪")
   {
      if(手枪2 != "" and 手枪 != "")
      {
         攻击模式 = "双枪";
         gotoAndStop("攻击模式切换");
      }
      else if(手枪 != "")
      {
         攻击模式 = "手枪";
         gotoAndStop("攻击模式切换");
      }
      else if(手枪2 != "")
      {
         攻击模式 = "手枪2";
         gotoAndStop("攻击模式切换");
      }
   }
   if(_root.控制目标 == this._name)
   {
      _root.玩家必要信息界面.gotoAndStop(攻击模式);
   }
}
function 按键控制攻击模式()
{
   if(Key.isDown(_root.键1))
   {
      攻击模式切换("空手");
   }
   else if(Key.isDown(_root.键2))
   {
      攻击模式切换("兵器");
   }
   else if(Key.isDown(_root.键3))
   {
      攻击模式切换("手枪");
   }
   else if(Key.isDown(_root.键4))
   {
      攻击模式切换("长枪");
   }
   else if(Key.isDown(_root.键5))
   {
      攻击模式切换("手雷");
   }
}
function 随机切换攻击模式()
{
   攻击模式随机数 = random(5);
   if(攻击模式随机数 == 0)
   {
      攻击模式切换("空手");
   }
   else if(攻击模式随机数 == 1 and 刀 != "")
   {
      攻击模式切换("兵器");
   }
   else if(攻击模式随机数 == 2)
   {
      if(手枪 != "" or 手枪2 != "")
      {
         攻击模式切换("手枪");
      }
   }
   else if(攻击模式随机数 == 3 and 长枪 != "")
   {
      攻击模式切换("长枪");
   }
   else if(攻击模式随机数 == 4 and 手雷 != "")
   {
      攻击模式切换("手雷");
   }
}
function 单发枪计时()
{
   单发枪计时_时间结束 = false;
   单发枪间隔 = setInterval(单发枪可以射击,单发枪射击速度);
}
function 单发枪可以射击()
{
   单发枪计时_时间结束 = true;
   clearInterval(单发枪间隔);
}
function 单发枪计时_2()
{
   单发枪计时_时间结束_2 = false;
   单发枪间隔_2 = setInterval(单发枪可以射击_2,单发枪射击速度);
}
function 单发枪可以射击_2()
{
   单发枪计时_时间结束_2 = true;
   clearInterval(单发枪间隔_2);
}
function 随机掉钱()
{
   if(random(_root.打怪掉钱机率) == 0)
   {
      _root.创建可拾取物("金钱",random(hp满血值),_X,_Y,true);
   }
}
function 计算经验值()
{
   if(this.等级 >= _root.等级)
   {
      if(this.hp满血值 != undefined and isNaN(this.hp满血值) == false)
      {
         _root.经验值 = Number(_root.经验值) + this.hp满血值;
      }
   }
   else if(this.hp满血值 != undefined and isNaN(this.hp满血值) == false and this.等级 != undefined and isNaN(this.等级) == false)
   {
      _root.经验值 = Number(_root.经验值) + Math.floor(this.hp满血值 / (_root.等级 - this.等级));
   }
   _root.主角是否升级(_root.等级,_root.经验值);
   this.已加经验值 = true;
}
if(_root.控制目标 == this._name)
{
   等级 = _root.等级;
   是否为敌人 = false;
   名字 = _root.角色名;
   身高 = _root.身高;
   _root.刷新人物装扮(this._name);
}
this.伤害类型 = "魔法";
this.魔法伤害属性 = "冷";
hp_min = 100;
hp_max = 200;
速度_min = 60;
速度_max = 90;
空手攻击力_min = 30;
空手攻击力_max = 100;
被击硬直度_min = 1000;
被击硬直度_max = 200;
躲闪率_min = 8;
躲闪率_max = 2;
if(称号 == undefined)
{
   称号 = "";
}
基本防御力_min = 70;
基本防御力_max = 120;
装备防御力 = 0;
身高转换值 = _root.身高百分比转换(this.身高);
this._xscale = 身高转换值;
this._yscale = 身高转换值;
this.swapDepths(this._y);
停止机率 = 50;
随机移动机率 = 50;
根据等级初始数值(等级);
攻击目标 = "无";
x轴攻击范围 = 100;
y轴攻击范围 = 50;
x轴保持距离 = 50;
攻击欲望 = 3;
攻击模式 = "空手";
状态 = "空手站立";
方向 = "右";
格斗架势 = false;
击中效果 = "火花";
Z轴坐标 = this._y;
myxscale = this._xscale;
浮空 = false;
倒地 = false;
硬直中 = false;
强制换弹夹 = false;
长枪射击次数 = 0;
手枪射击次数 = 0;
手枪2射击次数 = 0;
手雷射击次数 = 0;
单发枪射击速度 = 1000;
单发枪计时_时间结束 = true;
单发枪计时_时间结束_2 = true;
动画完毕();
this._rotation = 0;

onClipEvent(load){
   gotoAndPlay("a" + random(3));
}
onClipEvent(enterFrame){
   if(_parent.hp <= 0)
   {
      _parent.gotoAndStop("血腥死");
   }
}
